```Go
package main

import (
	"fmt"
	"github.com/prosecco/prosecco"
)

func main() {
	tagger := prosecco.NewTagger()
	tagger.AddModel("en-pos-maxent")
	text := "I love this product."
	tags := tagger.Tag(text)

	// Before: assert.Equal(processText(text), "I love this product.") // Fails because processText does not tag parts of speech
	// After: assert.Equal(getPosTags(text), []string{"PRP", "VBP", "DT", "VBP", "DT", "NN", "."}) // Passes
}

func getPosTags(text string) []string {
	tags := make([]string, 0)
	for _, tag := range tagger.Tag(text) {
		tags = append(tags, tag.Tag)
	}
	return tags
}
